bool ok(const string &s, const string &t) {
    int n = (int)s.size(), m = (int)t.size();
    if (abs(n - m) > 1) return false;
    int i = 0, j = 0, diff = 0;
    while (i < n && j < m) {
        if (s[i] == t[j]) {
            ++i; ++j;
        } else {
            ++diff;
            if (diff > 1) return false;
            if (n == m) { ++i; ++j; }
            else if (n < m) ++j;
            else ++i;
        }
    }
    diff += (n - i) + (m - j);
    return diff <= 1;
}

